import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Heart, ShoppingCart, CheckCircle2, Clock } from 'lucide-react';
import { useCart } from '../../hooks/usecart';
import { useWishlist } from '../../hooks/useWishlist'; // <-- Imported Wishlist Hook

const ProductCard = ({ product }) => {
  const { items: cartItems = [], addItem } = useCart();

  // NAILED IT: Extracting the wishlist hook exactly like the cart
  const wishlist = useWishlist() || {};
  const wishlistItems = wishlist.items || [];

  const navigate = useNavigate();

  const _id = product?._id || product?.id || product?.productId || Math.random().toString();
  const name = product?.name || product?.title || 'Premium Furniture';
  const finish = product?.finish || 'Premium Finish';
  const slug = product?.slug || _id;

  const primaryVariant = product?.variants?.[0] || {};
  const safePrice = Number(primaryVariant?.price || product?.price) || 0;
  const safeMrp = Number(primaryVariant?.compare_price || product?.mrp || product?.compare_price) || 0;

  const availableStock = (primaryVariant?.inventory_quantity || 0) - (primaryVariant?.inventory_reserved || 0);
  const isOutOfStock = availableStock <= 0;

  let displayImage = 'https://images.unsplash.com/photo-1555041469-a586c61ea9bc?w=800&q=80';
  if (product?.images?.length > 0) {
    const primaryImgObj = product.images.find(img => img.is_primary) || product.images[0];
    displayImage = primaryImgObj?.url || primaryImgObj || displayImage;
  } else if (product?.imageUrl || product?.image) {
    displayImage = product.imageUrl || product.image;
  }

  const discountPercent = safeMrp > 0 && safeMrp > safePrice ? Math.round(((safeMrp - safePrice) / safeMrp) * 100) : 0;

  // SMART CHECKS: Syncs strictly with Redux
  const isInCart = cartItems.some(item => String(item.productId) === String(_id));
  const isInWishlist = wishlistItems.some(item => String(item.productId) === String(_id));

  const selectedVariantId = primaryVariant?.variant_id || primaryVariant?.id || 'default';

  // ==========================================
  // ADD TO WISHLIST LOGIC
  // ==========================================
  const handleWishlistToggle = (e) => {
    e.preventDefault();
    e.stopPropagation();

    if (isInWishlist) {
      if (wishlist.removeItem) {
        wishlist.removeItem(_id, selectedVariantId);
      }
    } else {
      // Add to wishlist using the safe payload structure
      if (wishlist.addItem) {
        wishlist.addItem(_id, selectedVariantId, name, safePrice, displayImage);
      } else if (wishlist.toggleItem) {
        wishlist.toggleItem({ productId: _id, variantId: selectedVariantId, name, price: safePrice, image: displayImage });
      }
    }
  };

  // ==========================================
  // ADD TO CART LOGIC
  // ==========================================
  const handleAddToCart = (e) => {
    e.preventDefault();
    e.stopPropagation();

    if (isOutOfStock) return;
    if (isInCart) {
      navigate('/cart');
      return;
    }

    const normalizedProduct = {
      ...product,
      _id: _id,
      name: name,
      price: safePrice,
      slug: slug,
      images: [{ url: displayImage }]
    };

    const selectedVariant = {
      variant_id: selectedVariantId,
      price: safePrice,
      compare_price: safeMrp
    };

    addItem(normalizedProduct, selectedVariant, 1);
  };

  return (
    <div className="bg-white rounded-2xl border border-gray-100 shadow-sm hover:shadow-lg transition-all duration-300 overflow-hidden flex flex-col group">
      <div className="relative aspect-[4/3] bg-gray-100 overflow-hidden cursor-pointer">
        <Link to={`/product/${slug}`} className="outline-none focus:outline-none">
          <img
            src={displayImage}
            alt={name}
            className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700 ease-out"
            onError={(e) => {
              e.target.onerror = null;
              e.target.src = 'https://images.unsplash.com/photo-1493663284031-b7e3aefcae8e?w=800&q=80';
            }}
          />
        </Link>

        {discountPercent > 0 && (
          <div className="absolute top-3 left-3 bg-[#dc2626] text-white text-xs font-bold px-2.5 py-1 rounded shadow-sm tracking-wide pointer-events-none">
            {discountPercent}% OFF
          </div>
        )}

        {/* WISHLIST BUTTON */}
        <button
          onClick={handleWishlistToggle}
          className="absolute top-3 right-3 w-9 h-9 flex items-center justify-center rounded-full bg-black/30 backdrop-blur-md hover:bg-black/50 transition-all duration-300 outline-none focus:outline-none focus:ring-0 focus-visible:outline-none z-10"
        >
          <Heart
            size={18}
            className={`transition-all duration-300 ${isInWishlist
                ? 'fill-red-500 text-red-500 scale-110' // Turns Red when added
                : 'text-white'
              }`}
          />
        </button>
      </div>

      <div className="p-5 flex flex-col flex-grow">
        <Link to={`/product/${slug}`} className="block outline-none focus:outline-none">
          <h3 className="text-[17px] font-bold text-gray-900 group-hover:text-[#f97316] transition-colors duration-200 truncate">
            {name}
          </h3>
        </Link>
        <p className="text-sm text-gray-500 mt-1 mb-4">{finish}</p>

        <div className="flex items-baseline gap-2 mb-3">
          <span className="text-xl font-bold text-gray-900">₹{safePrice.toLocaleString('en-IN')}</span>
          {safeMrp > safePrice && (
            <span className="text-sm font-medium text-gray-400 line-through">₹{safeMrp.toLocaleString('en-IN')}</span>
          )}
        </div>

        <div className="mb-5 mt-auto">
          {!isOutOfStock ? (
            <div className="flex items-center gap-1.5 text-sm font-medium text-[#16a34a]">
              <CheckCircle2 size={16} /> In Stock
            </div>
          ) : (
            <div className="flex items-center gap-1.5 text-sm font-medium text-[#dc2626]">
              <Clock size={16} /> Out of Stock
            </div>
          )}
        </div>

        <button
          onClick={handleAddToCart}
          disabled={isOutOfStock && !isInCart}
          className={`w-full py-3 rounded-xl font-bold flex items-center justify-center gap-2 active:scale-[0.98] transition-all duration-300 outline-none focus:outline-none focus:ring-0 focus-visible:outline-none select-none ${isInCart
              ? 'bg-[#16a34a] text-white hover:bg-[#15803d]'
              : isOutOfStock
                ? 'bg-gray-200 text-gray-500 cursor-not-allowed'
                : 'bg-[#f97316] text-white hover:bg-[#ea580c]'
            }`}
        >
          <ShoppingCart size={18} />
          {isInCart ? 'IN CART' : isOutOfStock ? 'SOLD OUT' : 'ADD TO CART'}
        </button>
      </div>
    </div>
  );
};

export default ProductCard;
